    const orderA = businessOrder[a.business];
    const orderB = businessOrder[b.business];
    if (orderA !== orderB) {
      return orderA - orderB;
    } else {
      return a.code.localeCompare(b.code);
    }
  });

  return validCoupons.map(c => c.code);
}
