```typescript
function solve(code: string[], businessLine: string[], isActive: boolean[]): string[] {
  const allowedBusinessLines = ["electronics", "grocery", "pharmacy", "restaurant"];
  const codeRegex = /^[a-zA-Z0-9_]+$/;
  const businessOrder = {
    "electronics": 0,
    "grocery": 1,
    "pharmacy": 2,
    "restaurant": 3
  };

  const validCoupons = code
    .map((c, i) => {
      const business = businessLine[i];
      const active = isActive[i];
      if (c === "" || !codeRegex.test(c)) {
        return null;
      }
      if (!allowedBusinessLines.includes(business)) {
        return null;
      }
      if (!active) {
        return null;
      }
      return { code: c, business };
    })
    .filter(c => c !== null);

  validCoupons.sort((a, b) => {
    const orderA = businessOrder[a.business];
    const orderB = businessOrder[b.business];
    if (orderA !== orderB) {
      return orderA - orderB;
    } else {
      return a.code.localeCompare(b.code);
    }
  });

  return validCoupons.map(c => c.code);
}
```

